/**
 * SkeletonUI — Comprehensive skeleton loading components for Aura Alpha
 *
 * Variants:
 *   SkeletonRow       — table row with N pulsing bars
 *   SkeletonCard      — card shape with title/body/metric bars
 *   SkeletonChart     — chart placeholder with faux axes
 *   SkeletonMetric    — stat tile placeholder (label + value)
 *   SkeletonTablePage — full table page skeleton (metric row + header + rows)
 *   SkeletonCardGrid  — grid of skeleton cards
 *
 * Theme: dark (#111A24 base, #1F2A37 shimmer), opacity pulse 0.3-0.7 over 1.5s
 */

const C = {
  bg: '#0B0F14',
  surface: '#0F1620',
  base: '#111A24',
  shimmer: '#1F2A37',
  border: '#1F2A37',
};

const pulseKeyframes = `
  @keyframes skeletonPulse {
    0%, 100% { opacity: 0.3; }
    50% { opacity: 0.7; }
  }
`;

const pulseStyle = {
  animation: 'skeletonPulse 1.5s ease-in-out infinite',
  backgroundColor: C.base,
  borderRadius: 6,
};

function Bar({ width = '100%', height = 14, style = {}, delay = 0 }) {
  return (
    <div
      style={{
        ...pulseStyle,
        width,
        height,
        animationDelay: `${delay}s`,
        ...style,
      }}
    />
  );
}

/* ────────────────────────────────────────────────────────────
   SkeletonRow — single table row with N pulsing bars
   ──────────────────────────────────────────────────────────── */
export function SkeletonRow({ cols = 6, height = 14 }) {
  const widths = ['60%', '80%', '50%', '70%', '45%', '55%', '65%', '40%'];
  return (
    <tr>
      {Array.from({ length: cols }).map((_, i) => (
        <td
          key={i}
          style={{
            padding: '10px 12px',
            borderBottom: `1px solid ${C.border}`,
          }}
        >
          <Bar
            width={widths[i % widths.length]}
            height={height}
            delay={i * 0.08}
          />
        </td>
      ))}
    </tr>
  );
}

/* ────────────────────────────────────────────────────────────
   SkeletonCard — card shape with title, body, and metric bars
   ──────────────────────────────────────────────────────────── */
export function SkeletonCard({ width = '100%', height, style = {} }) {
  return (
    <div
      aria-busy="true"
      aria-label="Loading card"
      style={{
        width,
        minHeight: height || 160,
        borderRadius: 10,
        backgroundColor: C.surface,
        border: `1px solid ${C.border}`,
        padding: 16,
        display: 'flex',
        flexDirection: 'column',
        gap: 12,
        boxSizing: 'border-box',
        ...style,
      }}
    >
      <Bar width="40%" height={10} delay={0} />
      <Bar width="70%" height={20} delay={0.1} />
      <div style={{ display: 'flex', gap: 12, marginTop: 8 }}>
        <Bar width="30%" height={12} delay={0.2} />
        <Bar width="25%" height={12} delay={0.25} />
        <Bar width="20%" height={12} delay={0.3} />
      </div>
    </div>
  );
}

/* ────────────────────────────────────────────────────────────
   SkeletonChart — chart placeholder with faux axes
   ──────────────────────────────────────────────────────────── */
export function SkeletonChart({ height = 200 }) {
  return (
    <div
      aria-busy="true"
      aria-label="Loading chart"
      style={{
        width: '100%',
        height,
        borderRadius: 10,
        backgroundColor: C.surface,
        border: `1px solid ${C.border}`,
        position: 'relative',
        overflow: 'hidden',
      }}
    >
      {/* Y-axis labels */}
      <div style={{ position: 'absolute', left: 12, top: 16, display: 'flex', flexDirection: 'column', gap: 24 }}>
        <Bar width={36} height={10} delay={0} />
        <Bar width={30} height={10} delay={0.1} />
        <Bar width={36} height={10} delay={0.2} />
        <Bar width={28} height={10} delay={0.3} />
      </div>
      {/* Faux chart area */}
      <div
        style={{
          position: 'absolute',
          left: 60,
          right: 16,
          top: 16,
          bottom: 32,
          ...pulseStyle,
          borderRadius: 6,
          animationDelay: '0.15s',
        }}
      />
      {/* X-axis labels */}
      <div style={{ position: 'absolute', bottom: 10, left: 60, right: 16, display: 'flex', justifyContent: 'space-between' }}>
        {Array.from({ length: 5 }).map((_, i) => (
          <Bar key={i} width={28} height={8} delay={0.1 * i} />
        ))}
      </div>
    </div>
  );
}

/* ────────────────────────────────────────────────────────────
   SkeletonMetric — single stat tile placeholder (label + value)
   ──────────────────────────────────────────────────────────── */
export function SkeletonMetric({ delay = 0 }) {
  return (
    <div
      aria-busy="true"
      style={{
        flex: '1 1 0',
        minWidth: 120,
        backgroundColor: C.surface,
        border: `1px solid ${C.border}`,
        borderRadius: 10,
        padding: '14px 18px',
        display: 'flex',
        flexDirection: 'column',
        gap: 8,
      }}
    >
      <Bar width="55%" height={10} delay={delay} />
      <Bar width="40%" height={22} delay={delay + 0.1} />
    </div>
  );
}

/* ────────────────────────────────────────────────────────────
   SkeletonMetricRow — row of metric tiles
   ──────────────────────────────────────────────────────────── */
export function SkeletonMetricRow({ count = 4 }) {
  return (
    <div style={{ display: 'flex', gap: 16, flexWrap: 'wrap' }}>
      {Array.from({ length: count }).map((_, i) => (
        <SkeletonMetric key={i} delay={i * 0.1} />
      ))}
    </div>
  );
}

/* ────────────────────────────────────────────────────────────
   SkeletonTablePage — full table page: metric row + table
   Used for Positions, Orders, Watchlists, Alerts pages
   ──────────────────────────────────────────────────────────── */
export function SkeletonTablePage({
  title,
  metricCount = 4,
  cols = 6,
  rows = 8,
}) {
  const body = "'Plus Jakarta Sans', sans-serif";
  return (
    <>
      <style>{pulseKeyframes}</style>
      <div
        style={{
          height: '100%',
          display: 'flex',
          flexDirection: 'column',
          overflow: 'hidden',
          padding: '20px 24px',
          gap: 16,
          backgroundColor: C.bg,
          fontFamily: body,
        }}
      >
        {/* Title skeleton */}
        {title ? (
          <h1 style={{ margin: 0, fontSize: 22, fontWeight: 700, color: '#E5E7DB' }}>
            {title}
          </h1>
        ) : (
          <Bar width={200} height={24} delay={0} />
        )}

        {/* Metric cards row */}
        {metricCount > 0 && <SkeletonMetricRow count={metricCount} />}

        {/* Table skeleton */}
        <div
          style={{
            flex: 1,
            minHeight: 0,
            backgroundColor: C.surface,
            border: `1px solid ${C.border}`,
            borderRadius: 10,
            overflow: 'hidden',
          }}
        >
          <table style={{ width: '100%', borderCollapse: 'collapse' }}>
            <thead>
              <tr>
                {Array.from({ length: cols }).map((_, i) => (
                  <th
                    key={i}
                    style={{
                      padding: '10px 12px',
                      borderBottom: `1px solid ${C.border}`,
                      backgroundColor: C.surface,
                    }}
                  >
                    <Bar width="70%" height={10} delay={i * 0.05} />
                  </th>
                ))}
              </tr>
            </thead>
            <tbody>
              {Array.from({ length: rows }).map((_, r) => (
                <SkeletonRow key={r} cols={cols} />
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </>
  );
}

/* ────────────────────────────────────────────────────────────
   SkeletonCardGrid — grid of skeleton cards
   Used for Strategy Catalogue grid view, etc.
   ──────────────────────────────────────────────────────────── */
export function SkeletonCardGrid({ count = 9, columns = 'repeat(auto-fill, minmax(300px, 1fr))' }) {
  return (
    <>
      <style>{pulseKeyframes}</style>
      <div style={{ display: 'grid', gridTemplateColumns: columns, gap: 16 }}>
        {Array.from({ length: count }).map((_, i) => (
          <SkeletonCard key={i} style={{ animationDelay: `${i * 0.06}s` }} />
        ))}
      </div>
    </>
  );
}

